dotenv.config();

const app = express();
const PORT = 3000;

app.use(express.json());

// API endpoint for real compilation via oxide-engine Rust backend
app.post("/api/compiler/compile", async (req: any, res: any) => {
  try {
    const { files, command } = req.body;
    if (!files || !Array.isArray(files)) {
      res.status(400).json({ error: "Files array is required" });
      return;
    }

    const enginePath = path.join(process.cwd(), "oxide-engine", "target", "release", "oxide-engine");
    const binary = fs.existsSync(enginePath) ? enginePath : "cargo";
    const spawnArgs = binary === "cargo" ? ["run", "--release", "--quiet"] : [];
    const cwd = binary === "cargo" ? path.join(process.cwd(), "oxide-engine") : process.cwd();

    const child = spawn(binary, spawnArgs, {
      cwd,
      env: process.env,
    });

    let stdout = "";
    let stderr = "";

    child.stdout.on("data", (data: Buffer) => { stdout += data.toString(); });
    child.stderr.on("data", (data: Buffer) => { stderr += data.toString(); });

    child.stdin.write(JSON.stringify({ files, command: command || "" }));
    child.stdin.end();

    const code = await new Promise<number>((resolve) => {
      child.on("close", (c) => resolve(c ?? 1));
      child.on("error", () => resolve(1));
    });

    if (code !== 0 || stdout.trim() === "") {
      res.status(500).json({
        error: stderr || "oxide-engine failed to produce output",
        stdout,
        stderr,
        exitCode: code,
        success: false,
      });
      return;
    }

    try {
      const report = JSON.parse(stdout);
      res.json(report);
    } catch (parseErr) {
      res.status(500).json({
        error: "Failed to parse oxide-engine output",
        raw: stdout,
        stderr,
      });
    }
  } catch (error: any) {
    console.error("Compile error:", error);
    res.status(500).json({ error: error.message || "Compiler backend failure" });
  }
});

// Resolve a language model from the user's AI config.
function resolveModel(customConfig?: any) {
  const provider = customConfig?.provider || "gemini-api";
  if (provider === "openai-compatible") {
    const baseUrl = customConfig?.baseUrl || process.env.OPENAI_BASE_URL || "https://api.openai.com/v1";
    const apiKey = customConfig?.apiKey || process.env.OPENAI_API_KEY || "";
    const model = customConfig?.model || "gpt-4o-mini";
    return createOpenAI({ baseURL: baseUrl, apiKey }).chat(model);
  }
  // Default to Google Gemini via AI SDK
  const apiKey = customConfig?.geminiApiKey || process.env.GEMINI_API_KEY || "dummy_key";
  const baseURL = customConfig?.geminiBaseUrl || process.env.GEMINI_BASE_URL;
  const model = customConfig?.geminiModel || "gemini-3.5-flash";
  return createGoogleGenerativeAI({ apiKey, baseURL }).chat(model);
}

// Convert the frontend message format to AI SDK ModelMessage format.
function toModelMessages(messages: any[]): ModelMessage[] {
  return messages.map((m: any) => {
    if (m.role === "tool") {
      return { role: "tool", content: m.content } as ModelMessage;
    }
    return { role: m.role === "assistant" ? "assistant" : "user", content: m.content } as ModelMessage;
  });
}

// API endpoint for Agent actions using OpenHarness stateless Agent + Session streaming
app.post("/api/agent/chat", async (req: any, res: any) => {
  try {
    const { messages, customConfig, previousInteractionId, files, mcpServers, skills, subagents } = req.body;

    if (!messages || !Array.isArray(messages)) {
      res.status(400).json({ error: "Messages array is required" });
      return;
    }

    const model = resolveModel(customConfig);
    const workspaceConfig: AgentWorkspaceConfig = {
      files: files || [],
      mcpServers: mcpServers || {},
      skills: skills || undefined,
      subagents: subagents || undefined,
      todoStoreId: previousInteractionId || "oxide"
    };

    const { agent, getFiles } = await buildOxideAgent(model, workspaceConfig);

    const session = new Session({
      agent,
      sessionId: previousInteractionId || `oxide-${Date.now()}`,
      contextWindow: 128_000
    });

    const modelMessages = toModelMessages(messages);
    const userPrompt = messages[messages.length - 1]?.content || "";

    // Stream AI SDK 5 UI message chunks back to the frontend.
    const response = createUIMessageStreamResponse({
      stream: sessionEventsToUIStream(session.send(userPrompt, { signal: req.signal }), { signal: req.signal }),
      headers: {
        "X-Session-Id": session.sessionId,
        "X-OpenHarness-Version": "0.7.0"
      }
    });

    // After stream completes, the response is sent. We also need to ensure the
    // agent's MCP connections are closed. Express doesn't expose a simple
    // post-response hook, so we attach a close listener on the response.
    res.on("close", async () => {
      await agent.close();
    });

    response.body?.pipeTo(
      new WritableStream({
        write(chunk) {
          if (!res.writableEnded) res.write(chunk);
        },
        close() {
          if (!res.writableEnded) {
            res.setHeader("X-Workspace-Files", JSON.stringify(getFiles()));
            res.end();
          }
        },
        abort() {
          if (!res.writableEnded) res.end();
        }
      })
    );
  } catch (error: any) {
    console.error("Agent chat error:", error);
    res.status(500).json({ error: error.message || "Internal server error" });
  }
});


// One-shot command execution for the interactive console
app.post("/api/terminal/exec", async (req: any, res: any) => {
  try {
    const { command, cwd } = req.body;
    if (!command || typeof command !== "string") {
      res.status(400).json({ error: "command is required" });
      return;
    }

    const workingDir = cwd && typeof cwd === "string" ? path.resolve(cwd) : process.cwd();
    if (!fs.existsSync(workingDir)) {
      res.status(400).json({ error: "cwd does not exist" });
      return;
    }

    res.setHeader("Content-Type", "application/x-ndjson");
    res.setHeader("Cache-Control", "no-cache");
    res.setHeader("Connection", "keep-alive");
    res.status(200);

    const child = spawn(command, { shell: true, cwd: workingDir, env: process.env });

    const send = (obj: any) => {
      if (!res.writableEnded) res.write(JSON.stringify(obj) + "\n");
    };

    const buffers = { stdout: "", stderr: "" };
    const flush = (stream: "stdout" | "stderr") => {
      const parts = buffers[stream].split("\n");
      buffers[stream] = parts.pop() || "";
      for (const line of parts) {
        send({ type: stream, data: line });
      }
    };

    child.stdout.on("data", (data: Buffer) => {
      buffers.stdout += data.toString();
      flush("stdout");
    });

    child.stderr.on("data", (data: Buffer) => {
      buffers.stderr += data.toString();
      flush("stderr");
    });

    child.on("close", (code) => {
      flush("stdout");
      flush("stderr");
      send({ type: "exit", code: code ?? 0 });
      if (!res.writableEnded) res.end();
    });

    child.on("error", (err) => {
      send({ type: "error", message: err.message });
      send({ type: "exit", code: 1 });
      if (!res.writableEnded) res.end();
    });

    req.on("close", () => {
      if (!child.killed) child.kill();
    });
  } catch (error: any) {
    console.error("Terminal exec error:", error);
    res.status(500).json({ error: error.message || "Internal server error" });
  }
});

async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  const server = http.createServer(app);

  const wss = new WebSocketServer({ server, path: "/api/terminal/ws" });
  const terminals = new Map<string, pty.IPty>();

  const shell = process.platform === "win32" ? "powershell.exe" : process.env.SHELL || "/bin/bash";

  wss.on("connection", (ws, req) => {
    const url = new URL(req.url || "", `http://${req.headers.host}`);
    const sessionId = url.searchParams.get("session") || `tty-${Date.now()}`;

    let term = terminals.get(sessionId);
    if (!term) {
      term = pty.spawn(shell, [], {
        name: "xterm-color",
        cols: 80,
        rows: 24,
        cwd: process.cwd(),
        env: process.env as { [key: string]: string }
      });
      terminals.set(sessionId, term);
    }

    ws.on("message", (message) => {
      try {
        const data = JSON.parse(message.toString());
        if (data.type === "input" && typeof data.payload === "string") {
          term.write(data.payload);
        } else if (data.type === "resize" && typeof data.cols === "number" && typeof data.rows === "number") {
          term.resize(data.cols, data.rows);
        }
      } catch {
        term.write(message.toString());
      }
    });

    term.onData((data) => {
      if (ws.readyState === 1) ws.send(JSON.stringify({ type: "output", payload: data }));
    });

    term.onExit(({ exitCode }) => {
      if (ws.readyState === 1) ws.send(JSON.stringify({ type: "exit", exitCode }));
      ws.close();
    });

    ws.on("close", () => {
      // Keep the terminal alive for reconnection; clean up on explicit exit
    });

    ws.send(JSON.stringify({ type: "ready", sessionId }));
  });

  server.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on port ${PORT}`);
  });
}

startServer();
