import { Agent, createTodoTools, createSkillTool, discoverSkills, type SkillsConfig, type MCPServerConfig, type SubagentSource } from "@openharness/core";
import { tool, type ToolSet } from "ai";
import { z } from "zod";
import type { VirtualFile } from "../types";

// A simple virtual file system provider that operates on the workspace snapshot sent by the frontend.
class WorkspaceFsProvider {
  constructor(private files: Map<string, VirtualFile>) {}

  readFile(path: string): Promise<string> {
    const file = this.files.get(path);
    if (!file) throw new Error(`File not found: ${path}`);
    return Promise.resolve(file.content);
  }

  writeFile(path: string, content: string): Promise<void> {
    const existing = this.files.get(path);
    if (existing) {
      existing.content = content;
      existing.isDirty = true;
    } else {
      const name = path.split("/").pop() || path;
      this.files.set(path, {
        path,
        name,
        content,
        language: "typescript",
        isDirty: true,
        originalContent: content
      });
    }
    return Promise.resolve();
  }

  exists(path: string): Promise<boolean> {
    return Promise.resolve(this.files.has(path));
  }

  stat(path: string): Promise<{ isFile: boolean; isDirectory: boolean; size: number }> {
    const file = this.files.get(path);
    if (file) {
      return Promise.resolve({ isFile: true, isDirectory: false, size: Buffer.byteLength(file.content) });
    }
    return Promise.resolve({ isFile: false, isDirectory: false, size: 0 });
  }

  readdir(path: string): Promise<{ name: string; isFile: boolean; isDirectory: boolean }[]> {
    const seen = new Set<string>();
    const entries: { name: string; isFile: boolean; isDirectory: boolean }[] = [];
    for (const file of this.files.values()) {
      if (file.path.startsWith(path + "/") || file.path === path) {
        const relative = file.path.slice(path.length + 1);
        if (!relative) continue;
        const first = relative.split("/")[0];
        if (!seen.has(first)) {
          seen.add(first);
          const isDirectory = file.path !== path + "/" + first && !file.path.startsWith(path + "/" + first + "/");
          entries.push({ name: first, isFile: !isDirectory, isDirectory });
        }
      }
    }
    return Promise.resolve(entries);
  }

  mkdir(): Promise<void> {
    return Promise.resolve();
  }

  remove(path: string): Promise<void> {
    this.files.delete(path);
    return Promise.resolve();
  }

  rename(oldPath: string, newPath: string): Promise<void> {
    const file = this.files.get(oldPath);
    if (!file) throw new Error(`File not found: ${oldPath}`);
    const newName = newPath.split("/").pop() || newPath;
    file.path = newPath;
    file.name = newName;
    this.files.delete(oldPath);
    this.files.set(newPath, file);
    return Promise.resolve();
  }

  resolvePath(inputPath: string): string {
    return inputPath.startsWith("/") ? inputPath : inputPath;
  }
}

export interface AgentWorkspaceConfig {
  files: VirtualFile[];
  mcpServers?: Record<string, MCPServerConfig>;
  skills?: SkillsConfig;
  subagents?: SubagentSource;
  todoStoreId?: string | false;
  approvalCallback?: (toolCall: { toolName: string; toolCallId: string; input: unknown }) => boolean | Promise<boolean>;
}

const OXIDE_SYSTEM_PROMPT = `You are Oxide Agent, the ultra-fast AI assistant integrated within Oxide IDE (a lightweight high-performance developer sandbox). You operate inside a virtual workspace containing the user's project files. You have full access to tools that let you list, read, write, edit, and search files in the workspace. You can also manage todos, load skills, and delegate to subagents. Write optimized, production-ready code. Be highly precise. If requested, write complete files or clean git-style diffs. Explain instructions briefly.`;

export async function buildOxideAgent(
  model: any,
  workspaceConfig: AgentWorkspaceConfig
): Promise<{ agent: Agent; getFiles: () => VirtualFile[] }> {
  const filesMap = new Map<string, VirtualFile>();
  for (const file of workspaceConfig.files) {
    filesMap.set(file.path, file);
  }

  const fsProvider = new WorkspaceFsProvider(filesMap);

  // Build virtual workspace tools directly from the provider so the returned
  // files reflect the frontend's virtual workspace state.
  const workspaceTools = createWorkspaceTools(fsProvider);

  let extraTools: ToolSet = {};
  if (workspaceConfig.todoStoreId !== false) {
    const { todowrite, todoread } = createTodoTools({ sessionId: workspaceConfig.todoStoreId ?? "oxide" });
    extraTools = { ...extraTools, todowrite, todoread };
  }

  if (workspaceConfig.skills) {
    const discovered = await discoverSkills(workspaceConfig.skills);
    if (discovered.length > 0) {
      extraTools = { ...extraTools, skill: createSkillTool(discovered) };
    }
  }

  const agent = new Agent({
    name: "oxide",
    description: "Ultra-fast AI assistant for the Oxide IDE virtual workspace",
    model,
    systemPrompt: OXIDE_SYSTEM_PROMPT,
    tools: { ...workspaceTools, ...extraTools },
    maxSteps: 20,
    mcpServers: workspaceConfig.mcpServers,
    subagents: workspaceConfig.subagents,
    maxSubagentDepth: 2,
    approve: workspaceConfig.approvalCallback,
    onSubagentEvent: (path, event) => {
      // Subagent events will be streamed via the response transform.
      console.log("[subagent]", path.join("/"), event.type);
    }
  });

  return { agent, getFiles: () => Array.from(filesMap.values()) };
}

function createWorkspaceTools(fsProvider: WorkspaceFsProvider) {
  const readFile = tool({
    description: "Read the contents of a virtual workspace file by path.",
    inputSchema: z.object({
      path: z.string().describe("Workspace file path")
    }),
    execute: async ({ path }: { path: string }) => {
      try {
        const content = await fsProvider.readFile(path);
        return { path, content };
      } catch (err: any) {
        return { error: err.message, path };
      }
    }
  });

  const writeFile = tool({
    description: "Create or overwrite a virtual workspace file with the provided content.",
    inputSchema: z.object({
      path: z.string().describe("Workspace file path"),
      content: z.string().describe("Full file content")
    }),
    execute: async ({ path, content }: { path: string; content: string }) => {
      await fsProvider.writeFile(path, content);
      return { path, written: true };
    }
  });

  const editFile = tool({
    description: "Edit a virtual workspace file by replacing an exact string match.",
    inputSchema: z.object({
      path: z.string(),
      oldString: z.string(),
      newString: z.string(),
      replaceAll: z.boolean().optional().default(false)
    }),
    execute: async ({ path, oldString, newString, replaceAll }: { path: string; oldString: string; newString: string; replaceAll: boolean }) => {
      const content = await fsProvider.readFile(path);
      if (!content.includes(oldString)) {
        return { error: "oldString not found in file", path };
      }
      const updated = replaceAll ? content.replaceAll(oldString, newString) : content.replace(oldString, newString);
      await fsProvider.writeFile(path, updated);
      return { path, replacements: replaceAll ? content.split(oldString).length - 1 : 1 };
    }
  });

  const listFiles = tool({
    description: "List all virtual workspace files along with their paths and names.",
    inputSchema: z.object({}),
    execute: async () => {
      const files = await fsProvider.readdir("");
      return { files: files.map(f => ({ path: f.name, name: f.name })) };
    }
  });

  const deleteFile = tool({
    description: "Delete a virtual workspace file.",
    inputSchema: z.object({
      path: z.string()
    }),
    execute: async ({ path }: { path: string }) => {
      await fsProvider.remove(path);
      return { deleted: path };
    }
  });

  const renameFile = tool({
    description: "Rename a virtual workspace file.",
    inputSchema: z.object({
      oldPath: z.string(),
      newPath: z.string()
    }),
    execute: async ({ oldPath, newPath }: { oldPath: string; newPath: string }) => {
      await fsProvider.rename(oldPath, newPath);
      return { renamed: newPath };
    }
  });

  return { readFile, writeFile, editFile, listFiles, deleteFile, renameFile };
}
